var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SERVICEBOT_NPC_NULL_NULL","text":{"KOREA":"주문하신 주류를 가져왔습니다, 손님.","JPN":"ご注文のお酒をお持ちしました、お客様。","ENG":"The drink you ordered, sir.","TWN":"客人，這是您點的酒。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SERVICEBOT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SERVICEBOT_NPC_NULL_NULL","text":{"KOREA":"저희 호텔에서 즐거운 추억을 만드시길 바랍니다. 필요하실 때 불러 주십시오.","JPN":"当ホテルで楽しい時間をお過ごしください。必要な際はいつでもお呼びください。","ENG":"I hope you have a pleasant stay at our hotel. Please don't hesitate to call if you need any assistance.","TWN":"祝您在本飯店留下美好的回憶，有任何需要請隨時找我。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"SERVICEBOT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"어머, 요즘에는 이런 데서도 로봇으로 서빙을 해 주네.","JPN":"あら、最近はこういうところでもロボットを使っているのね。","ENG":"Oh my. They've got robot waiters even in places like this these days, huh?","TWN":"哇，最近連這種地方也使用機器人提供服務嗎？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"격식을 갖출 줄 모른다는 뜻이지.","JPN":"格式が高くないホテルってことだな。","ENG":"It shows they've got no class.","TWN":"一點都不像樣！"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"돈을 비싸게 받으면 사람을 써야지, 어디서 저런 고물을.","JPN":"客から高い金をもらっているなら人でもてなすべきだろう。あんなポンコツを使いやがって。","ENG":"For the price we're paying, they ought to use real people. Not just some second-rate junk like that.","TWN":"想賺錢還捨不得花錢請真人，用那種廢鐵。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기는 로봇만 보면 그렇게 못마땅해 하더라.","JPN":"ダーリンってロボットを見ると機嫌が悪くなるよね。","ENG":"You always get so cranky whenever you see a robot, babe.","TWN":"親愛的怎麼看到機器人就那麼上火？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"그런데 이런 술 정말 시켜도 괜찮아? 내 한 달 월급보다 비쌀 것 같은데……?","JPN":"ていうか、本当にこんな高いお酒を頼んでもいいの？　あたしの給料より高そうだけど……？","ENG":"Anyway, are you sure we can order a drink like this? It's got to cost more than I make in a month…","TWN":"不過點這種酒沒問題嗎？應該比我一個月的薪水還貴吧……？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흥. 말했잖아. 나랑 있을 때는 가격표에 눈길 주지 말라고.","JPN":"言っただろ。僕といる時は金なんか気にしなくていいって。","ENG":"Hmph. I told you. Don't pay any attention to the price tag when you're with me.","TWN":"哼哼。我不是說過嗎？跟我在一起的時候不用在乎價錢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내가 돈을 벌어서 어디다 쓰겠어? 가지고 싶은 건 전부 가졌는데?","JPN":"僕が稼いだお金さ。欲しい物は何だって買えるし、すでに持っている。","ENG":"Where else am I going to spend my money? I've already got everything I've ever wanted.","TWN":"不然我賺那麼多錢是要花到哪裡？我想要的東西都已經有啦！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"샤레이드에서 가장 주목 받는 신흥 기업의 대표, 3대가 쓰고도 남을 재산에, 자기처럼 아름다운 애인까지.","JPN":"シャレードで最も注目されている新興企業の代表、桁違いの財産に、ハニーのような美しい恋人まで。","ENG":"I'm the CEO of the hottest unicorn company in Charade. My fortune will last more than three generations. And I'm dating the most beautiful woman in the world.","TWN":"身為在查雷德最受矚目的新興企業代表，我的錢三代都花不光，還有像親愛的這樣的美人伴身邊。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"정말, 자기는 남들 다 듣는 데서 그런 부끄러운 말 하길 좋아하더라……","JPN":"もう～ダーリンったら～！　人目も気にしないで恥ずかしいこと言っちゃうんだから～！","ENG":"Aww, babe. You must enjoy making me blush, saying stuff like that in public all the time…","TWN":"討厭～親愛的真的很喜歡在人多的地方，說這種害羞的話……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아직 부끄러워하기에는 이르지. 지금부터가……","JPN":"恥ずかしがるにはまだはやい。これからが……","ENG":"It's a little early to get your skin flushed. We're just getting started…","TWN":"現在還不是害羞的時候，等下我……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하아, 업무 연락을 끊어 두는 걸 깜빡했군.","JPN":"はあ、業務連絡の通知を切っておくのをうっかり忘れてたな。","ENG":"Ugh… I forgot to turn off my work phone.","TWN":"哎呀，忘記把公務來電設為拒接。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"미안. 잠시 통화 좀 하고 올게.","JPN":"ごめんな。少し電話してくるよ。","ENG":"Sorry. I've got to take this call real quick.","TWN":"對不起，我去接個電話就回來。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"신경 쓰지 말고 천천히 해. 난 괜찮으니까.","JPN":"あたしのことは気にしないで、ゆっくり話してきてね。","ENG":"Don't worry about me and take your time. I'm fine with it.","TWN":"沒關係，慢慢來，不用在意我。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"셰나, 무슨 일이지? 이 연락처로 업무 얘기는 안 하겠다고 하지 않았나?","JPN":"シェナ、今度は何だ？　この連絡先では仕事の話をしないと言ったはずだが。","ENG":"What is it, Shena? Didn't I make it clear I won't talk shop on this number?","TWN":"世娜，什麼事？我不是說公司的事不要打這支電話嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음, 성능 좋은 아티팩트를 두고 그렇게 맨얼굴로 다닐 거야?","JPN":"ふ～ん、性能の良いアーティファクトがあるのに、そんな素顔でいるつもりなんだ？","ENG":"Hmm, why go around with that boring face of yours when you've got such a great artifact at your disposal?","TWN":"嗯，你放著那麼棒的人造神器不用，用真面目示人喔？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"}}}}]`);export{e as default};